from flask import Flask, request
from prometheus_client import start_http_server, Counter, generate_latest
import random

app = Flask(__name__)
start_http_server(8000)

REQUESTS = {}

@app.route('/metrics')
def metrics():
    return generate_latest()

@app.before_request
def track_requests():
    user_id = request.headers.get('User-Id', 'unknown')
    session_id = request.headers.get('Session-Id', 'unknown')
    path = request.path
    key = f"{user_id}_{session_id}_{path}"
    
    if key not in REQUESTS:
        REQUESTS[key] = Counter(f'requests_{key}', 'Number of requests to this endpoint for user-path combination')
        
    REQUESTS[key].inc()

@app.route('/')
def home():
    return "Hello, World!"

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)